// VPS Saisie — normalise + enrichit la soumission
const body = $input.first().json.body;

const now  = new Date().toISOString();
const date = body.date || now.split('T')[0];

// Calcul statut global (recalcul serveur — ne pas faire confiance au client)
const epis = body.epi_results || [];
const nMauvais = epis.filter(e => e.etat === 'Mauvais').length;
const nNon     = epis.filter(e => e.porte === 'NON').length;
const statut   = nMauvais === 0 ? 'Conforme' :
                 nMauvais === epis.length ? 'Non-conforme' : 'Partiel';

const record = {
  site:          body.site          || '',
  technicien:    body.technicien    || '',
  auditeur:      body.auditeur      || '',
  date_visite:   date,
  type_idx:      body.type_idx      ?? -1,
  type_label:    body.type_label    || '',
  remarque:      body.remarque      || '',
  epi_results:   JSON.stringify(epis),
  nb_epi:        epis.length,
  nb_mauvais:    nMauvais,
  nb_non_porte:  nNon,
  statut,
  submitted_at:  body.submitted_at || now,
  received_at:   now,
};

return [{ json: record }];
